VALUES
  ('dietitian-moex-00573', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關食品從業人員的教育訓練，下列敘述何者錯誤？', '["HACCP管制小組成員需具備30小時以上訓練合格證明", "管制小組成員平均每年只要受4小時的HACCP持續教育即可", "當年度HACCP持續教育時數可抵免衛生講習時數", "若無實施HACCP系統時，衛生管理人員只需有30小時以上之訓練合格證明即可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00574', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者屬糞便經口傳染病毒，且常見於秋、冬季節，容易在人口密集機構，如養護機構、護理機構等造成 腹瀉群聚事件？', '["諾羅病毒", "茲卡病毒", "禽流感病毒", "手足口症病毒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00575', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據食品良好衛生規範準則，有關清潔及消毒等化學物質及用具之管理，下列何者錯誤？', '["病媒防治使用之藥物，應符合農藥管理法及其相關法規之規定，並明確標示，存放於固定場所", "清潔劑、消毒劑及有毒化學物質，應符合相關主管機關之規定，並明確標示，存放於固定場所", "食品作業場所內，除維護衛生所必須使用之藥劑外，不得存放使用", "清潔、清洗及消毒用機具，不可與食品原料置於同一場所保存"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00576', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '管制作業區前應有泡鞋池，若使用氯化合物當消毒劑，有效餘氯濃度應在多少以上？', '["50 ppm", "100 ppm", "150 ppm", "200 ppm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00577', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關豬肉標示規範之敘述，下列何者錯誤？', '["豬肉原料來源之原產地，以「飼養地（國）」為認定標準", "含豬可食部位之包裝食品、散裝食品或直接供應飲食場所供應的食品，都應標示其豬可食部位之原產地", "採用豬可食部位為原料製得之明膠或豬肉香料等，得免標示豬原料原產地", "豬脂（油）產品須標示所使用豬油之原料原產地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00578', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據巧克力之品名及標示規定，下列敘述何者錯誤？', '["標示為「黑巧克力」者，其總可可固形物含量至少35%、可可脂至少18%、非脂可可固形物至少14%", "標示為「白巧克力」者，其可可脂含量至少20%、牛乳固形物至少14%", "標示為「牛奶巧克力」者，其總可可固形物含量至少25%、非脂可可固形物至少2.5%、牛乳固形物至少12%", "添加植物油取代可可脂之巧克力，其添加量超過該產品總重量之5%者：應於品名前加標示「代可可脂」字 樣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00579', 'dietitian', 'dietitian-moex-113-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '依據包裝食品營養標示應遵行事項之規定，4歲以上無特定族群的每日營養素攝取量之基準值，下列何者錯 誤？', '["蛋白質70公克", "脂肪60公克", "碳水化合物300公克", "鈉2,000毫克"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:51+00:00", "source_pdf_sha1": "dc7d36addeb7", "answer_pdf_sha1": "539ae8d64549", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00580', 'dietitian', 'dietitian-moex-112-4665e2ba', 'sub-dietitian-01', NULL, 'essay', '請闡述平均需要量（EstimatedAverageRequirement,EAR）及建議攝取量
